-- =============================================================================
-- 0010 — Tableau périodique : vraies familles + 119 éléments (G2.1)
-- =============================================================================
-- Corrige le mapping des familles vers les 10 slugs FR officiels
-- (sans accents pour SQL/URL) :
--   metaux-alcalins / metaux-alcalino-terreux / metaux-transition
--   metaux-post-transition / metalloides / non-metaux-reactifs
--   gaz-nobles / lanthanides / actinides / proprietes-inconnues
--
-- Source : src/data/periodic-table-lookup_1.json (Wikipedia/IUPAC, 119 él.)
-- Mapping diatomic + polyatomic nonmetal → non-metaux-reactifs (1 famille
-- visuelle pour faciliter le quizz, le détail diatomique reste accessible
-- via summary).
--
-- Ajoute 2 colonnes (idempotent) :
--   - wgrid_row / wgrid_col : grille longue 32 colonnes (usage futur,
--     pas affiché dans la version compacte 18×10).
--   - summary_fr : résumé FR (laissé en anglais pour l'instant ; la
--     colonne existe pour permettre une traduction manuelle ultérieure).
--
-- Idempotent : INSERT ... ON CONFLICT (numero_atomique) DO UPDATE SET …
-- Peut être rejouée sans risque.
-- =============================================================================

ALTER TABLE public.periodic_elements
  ADD COLUMN IF NOT EXISTS wgrid_row smallint,
  ADD COLUMN IF NOT EXISTS wgrid_col smallint,
  ADD COLUMN IF NOT EXISTS summary_fr text;

-- =============================================================================
-- UPSERT — 119 éléments avec familles FR officielles
-- =============================================================================

INSERT INTO public.periodic_elements (
  numero_atomique, symbole, nom, periode, groupe, famille,
  masse_atomique, etat_standard, grid_row, grid_col,
  wgrid_row, wgrid_col, summary_fr
) VALUES
  (1, 'H', 'Hydrogène', 1, 1, 'non-metaux-reactifs', 1.008, 'gaz', 1, 1, 1, 1, 'Hydrogen is a chemical element with chemical symbol H and atomic number 1. With an atomic weight of 1.00794 u, hydrogen is the lightest element on the periodic table. Its monatomic form (H) is the most abundant chemical substance in the Universe, constituting roughly 75% of all baryonic mass.'),
  (2, 'He', 'Hélium', 1, 18, 'gaz-nobles', 4.0026022, 'gaz', 1, 18, 1, 32, 'Helium is a chemical element with symbol He and atomic number 2. It is a colorless, odorless, tasteless, non-toxic, inert, monatomic gas that heads the noble gas group in the periodic table. Its boiling and melting points are the lowest among all the elements.'),
  (3, 'Li', 'Lithium', 2, 1, 'metaux-alcalins', 6.94, 'solide', 2, 1, 2, 1, 'Lithium (from Greek:λίθος lithos, "stone") is a chemical element with the symbol Li and atomic number 3. It is a soft, silver-white metal belonging to the alkali metal group of chemical elements. Under standard conditions it is the lightest metal and the least dense solid element.'),
  (4, 'Be', 'Béryllium', 2, 2, 'metaux-alcalino-terreux', 9.01218315, 'solide', 2, 2, 2, 2, 'Beryllium is a chemical element with symbol Be and atomic number 4. It is created through stellar nucleosynthesis and is a relatively rare element in the universe. It is a divalent element which occurs naturally only in combination with other elements in minerals.'),
  (5, 'B', 'Bore', 2, 13, 'metalloides', 10.81, 'solide', 2, 13, 2, 27, 'Boron is a metalloid chemical element with symbol B and atomic number 5. Produced entirely by cosmic ray spallation and supernovae and not by stellar nucleosynthesis, it is a low-abundance element in both the Solar system and the Earth''s crust. Boron is concentrated on Earth by the water-solubility of its more common naturally occurring compounds, the borate minerals.'),
  (6, 'C', 'Carbone', 2, 14, 'non-metaux-reactifs', 12.011, 'solide', 2, 14, 2, 28, 'Carbon (from Latin:carbo "coal") is a chemical element with symbol C and atomic number 6. On the periodic table, it is the first (row 2) of six elements in column (group) 14, which have in common the composition of their outer electron shell. It is nonmetallic and tetravalent—making four electrons available to form covalent chemical bonds.'),
  (7, 'N', 'Azote', 2, 15, 'non-metaux-reactifs', 14.007, 'gaz', 2, 15, 2, 29, 'Nitrogen is a chemical element with symbol N and atomic number 7. It is the lightest pnictogen and at room temperature, it is a transparent, odorless diatomic gas. Nitrogen is a common element in the universe, estimated at about seventh in total abundance in the Milky Way and the Solar System.'),
  (8, 'O', 'Oxygène', 2, 16, 'non-metaux-reactifs', 15.999, 'gaz', 2, 16, 2, 30, 'Oxygen is a chemical element with symbol O and atomic number 8. It is a member of the chalcogen group on the periodic table and is a highly reactive nonmetal and oxidizing agent that readily forms compounds (notably oxides) with most elements. By mass, oxygen is the third-most abundant element in the universe, after hydrogen and helium.'),
  (9, 'F', 'Fluor', 2, 17, 'non-metaux-reactifs', 18.9984031636, 'gaz', 2, 17, 2, 31, 'Fluorine is a chemical element with symbol F and atomic number 9. It is the lightest halogen and exists as a highly toxic pale yellow diatomic gas at standard conditions. As the most electronegative element, it is extremely reactive:almost all other elements, including some noble gases, form compounds with fluorine.'),
  (10, 'Ne', 'Néon', 2, 18, 'gaz-nobles', 20.17976, 'gaz', 2, 18, 2, 32, 'Neon is a chemical element with symbol Ne and atomic number 10. It is in group 18 (noble gases) of the periodic table. Neon is a colorless, odorless, inert monatomic gas under standard conditions, with about two-thirds the density of air.'),
  (11, 'Na', 'Sodium', 3, 1, 'metaux-alcalins', 22.989769282, 'solide', 3, 1, 3, 1, 'Sodium /ˈsoʊdiəm/ is a chemical element with symbol Na (from Ancient Greek Νάτριο) and atomic number 11. It is a soft, silver-white, highly reactive metal. In the Periodic table it is in column 1 (alkali metals), and shares with the other six elements in that column that it has a single electron in its outer shell, which it readily donates, creating a positively charged atom - a cation.'),
  (12, 'Mg', 'Magnésium', 3, 2, 'metaux-alcalino-terreux', 24.305, 'solide', 3, 2, 3, 2, 'Magnesium is a chemical element with symbol Mg and atomic number 12. It is a shiny gray solid which bears a close physical resemblance to the other five elements in the second column (Group 2, or alkaline earth metals) of the periodic table:they each have the same electron configuration in their outer electron shell producing a similar crystal structure. Magnesium is the ninth most abundant element in the universe.'),
  (13, 'Al', 'Aluminium', 3, 13, 'metaux-post-transition', 26.98153857, 'solide', 3, 13, 3, 27, 'Aluminium (or aluminum; see different endings) is a chemical element in the boron group with symbol Al and atomic number 13. It is a silvery-white, soft, nonmagnetic, ductile metal. Aluminium is the third most abundant element (after oxygen and silicon), and the most abundant metal, in the Earth''s crust.'),
  (14, 'Si', 'Silicium', 3, 14, 'metalloides', 28.085, 'solide', 3, 14, 3, 28, 'Silicon is a chemical element with symbol Si and atomic number 14. It is a tetravalent metalloid, more reactive than germanium, the metalloid directly below it in the table. Controversy about silicon''s character dates to its discovery.'),
  (15, 'P', 'Phosphore', 3, 15, 'non-metaux-reactifs', 30.9737619985, 'solide', 3, 15, 3, 29, 'Phosphorus is a chemical element with symbol P and atomic number 15. As an element, phosphorus exists in two major forms—white phosphorus and red phosphorus—but due to its high reactivity, phosphorus is never found as a free element on Earth. Instead phosphorus-containing minerals are almost always present in their maximally oxidised state, as inorganic phosphate rocks.'),
  (16, 'S', 'Soufre', 3, 16, 'non-metaux-reactifs', 32.06, 'solide', 3, 16, 3, 30, 'Sulfur or sulphur (see spelling differences) is a chemical element with symbol S and atomic number 16. It is an abundant, multivalent non-metal. Under normal conditions, sulfur atoms form cyclic octatomic molecules with chemical formula S8.'),
  (17, 'Cl', 'Chlore', 3, 17, 'non-metaux-reactifs', 35.45, 'gaz', 3, 17, 3, 31, 'Chlorine is a chemical element with symbol Cl and atomic number 17. It also has a relative atomic mass of 35.5. Chlorine is in the halogen group (17) and is the second lightest halogen following fluorine.'),
  (18, 'Ar', 'Argon', 3, 18, 'gaz-nobles', 39.9481, 'gaz', 3, 18, 3, 32, 'Argon is a chemical element with symbol Ar and atomic number 18. It is in group 18 of the periodic table and is a noble gas. Argon is the third most common gas in the Earth''s atmosphere, at 0.934% (9,340 ppmv), making it over twice as abundant as the next most common atmospheric gas, water vapor (which averages about 4000 ppmv, but varies greatly), and 23 times as abundant as the next most common non-condensing atmospheric gas, carbon dioxide (400 ppmv), and more than 500 times as abundant as the next most common noble gas, neon (18 ppmv).'),
  (19, 'K', 'Potassium', 4, 1, 'metaux-alcalins', 39.09831, 'solide', 4, 1, 4, 1, 'Potassium is a chemical element with symbol K (derived from Neo-Latin, kalium) and atomic number 19. It was first isolated from potash, the ashes of plants, from which its name is derived. In the Periodic table, potassium is one of seven elements in column (group) 1 (alkali metals):they all have a single valence electron in their outer electron shell, which they readily give up to create an atom with a positive charge - a cation, and combine with anions to form salts.'),
  (20, 'Ca', 'Calcium', 4, 2, 'metaux-alcalino-terreux', 40.0784, 'solide', 4, 2, 4, 2, 'Calcium is a chemical element with symbol Ca and atomic number 20. Calcium is a soft gray alkaline earth metal, fifth-most-abundant element by mass in the Earth''s crust. The ion Ca2+ is also the fifth-most-abundant dissolved ion in seawater by both molarity and mass, after sodium, chloride, magnesium, and sulfate.'),
  (21, 'Sc', 'Scandium', 4, 3, 'metaux-transition', 44.9559085, 'solide', 4, 3, 4, 17, 'Scandium is a chemical element with symbol Sc and atomic number 21. A silvery-white metallic d-block element, it has historically been sometimes classified as a rare earth element, together with yttrium and the lanthanoids. It was discovered in 1879 by spectral analysis of the minerals euxenite and gadolinite from Scandinavia.'),
  (22, 'Ti', 'Titane', 4, 4, 'metaux-transition', 47.8671, 'solide', 4, 4, 4, 18, 'Titanium is a chemical element with symbol Ti and atomic number 22. It is a lustrous transition metal with a silver color, low density and high strength. It is highly resistant to corrosion in sea water, aqua regia and chlorine.'),
  (23, 'V', 'Vanadium', 4, 5, 'metaux-transition', 50.94151, 'solide', 4, 5, 4, 19, 'Vanadium is a chemical element with symbol V and atomic number 23. It is a hard, silvery grey, ductile and malleable transition metal. The element is found only in chemically combined form in nature, but once isolated artificially, the formation of an oxide layer stabilizes the free metal somewhat against further oxidation.'),
  (24, 'Cr', 'Chrome', 4, 6, 'metaux-transition', 51.99616, 'solide', 4, 6, 4, 20, 'Chromium is a chemical element with symbol Cr and atomic number 24. It is the first element in Group 6. It is a steely-gray, lustrous, hard and brittle metal which takes a high polish, resists tarnishing, and has a high melting point.'),
  (25, 'Mn', 'Manganèse', 4, 7, 'metaux-transition', 54.9380443, 'solide', 4, 7, 4, 21, 'Manganese is a chemical element with symbol Mn and atomic number 25. It is not found as a free element in nature; it is often found in combination with iron, and in many minerals. Manganese is a metal with important industrial metal alloy uses, particularly in stainless steels.'),
  (26, 'Fe', 'Fer', 4, 8, 'metaux-transition', 55.8452, 'solide', 4, 8, 4, 22, 'Iron is a chemical element with symbol Fe (from Latin:ferrum) and atomic number 26. It is a metal in the first transition series. It is by mass the most common element on Earth, forming much of Earth''s outer and inner core.'),
  (27, 'Co', 'Cobalt', 4, 9, 'metaux-transition', 58.9331944, 'solide', 4, 9, 4, 23, 'Cobalt is a chemical element with symbol Co and atomic number 27. Like nickel, cobalt in the Earth''s crust is found only in chemically combined form, save for small deposits found in alloys of natural meteoric iron. The free element, produced by reductive smelting, is a hard, lustrous, silver-gray metal.'),
  (28, 'Ni', 'Nickel', 4, 10, 'metaux-transition', 58.69344, 'solide', 4, 10, 4, 24, 'Nickel is a chemical element with symbol Ni and atomic number 28. It is a silvery-white lustrous metal with a slight golden tinge. Nickel belongs to the transition metals and is hard and ductile.'),
  (29, 'Cu', 'Cuivre', 4, 11, 'metaux-transition', 63.5463, 'solide', 4, 11, 4, 25, 'Copper is a chemical element with symbol Cu (from Latin:cuprum) and atomic number 29. It is a soft, malleable and ductile metal with very high thermal and electrical conductivity. A freshly exposed surface of pure copper has a reddish-orange color.'),
  (30, 'Zn', 'Zinc', 4, 12, 'metaux-transition', 65.382, 'solide', 4, 12, 4, 26, 'Zinc, in commerce also spelter, is a chemical element with symbol Zn and atomic number 30. It is the first element of group 12 of the periodic table. In some respects zinc is chemically similar to magnesium:its ion is of similar size and its only common oxidation state is +2.'),
  (31, 'Ga', 'Gallium', 4, 13, 'metaux-post-transition', 69.7231, 'solide', 4, 13, 4, 27, 'Gallium is a chemical element with symbol Ga and atomic number 31. Elemental gallium does not occur in free form in nature, but as the gallium(III) compounds that are in trace amounts in zinc ores and in bauxite. Gallium is a soft, silvery metal, and elemental gallium is a brittle solid at low temperatures, and melts at 29.76 °C (85.57 °F) (slightly above room temperature).'),
  (32, 'Ge', 'Germanium', 4, 14, 'metalloides', 72.6308, 'solide', 4, 14, 4, 28, 'Germanium is a chemical element with symbol Ge and atomic number 32. It is a lustrous, hard, grayish-white metalloid in the carbon group, chemically similar to its group neighbors tin and silicon. Purified germanium is a semiconductor, with an appearance most similar to elemental silicon.'),
  (33, 'As', 'Arsenic', 4, 15, 'metalloides', 74.9215956, 'solide', 4, 15, 4, 29, 'Arsenic is a chemical element with symbol As and atomic number 33. Arsenic occurs in many minerals, usually in conjunction with sulfur and metals, and also as a pure elemental crystal. Arsenic is a metalloid.'),
  (34, 'Se', 'Sélénium', 4, 16, 'non-metaux-reactifs', 78.9718, 'solide', 4, 16, 4, 30, 'Selenium is a chemical element with symbol Se and atomic number 34. It is a nonmetal with properties that are intermediate between those of its periodic table column-adjacent chalcogen elements sulfur and tellurium. It rarely occurs in its elemental state in nature, or as pure ore compounds.'),
  (35, 'Br', 'Brome', 4, 17, 'non-metaux-reactifs', 79.904, 'liquide', 4, 17, 4, 31, 'Bromine (from Ancient Greek:βρῶμος, brómos, meaning "stench") is a chemical element with symbol Br, and atomic number 35. It is a halogen. The element was isolated independently by two chemists, Carl Jacob Löwig and Antoine Jerome Balard, in 1825–1826.'),
  (36, 'Kr', 'Krypton', 4, 18, 'gaz-nobles', 83.7982, 'gaz', 4, 18, 4, 32, 'Krypton (from Greek:κρυπτός kryptos "the hidden one") is a chemical element with symbol Kr and atomic number 36. It is a member of group 18 (noble gases) elements. A colorless, odorless, tasteless noble gas, krypton occurs in trace amounts in the atmosphere, is isolated by fractionally distilling liquefied air, and is often used with other rare gases in fluorescent lamps.'),
  (37, 'Rb', 'Rubidium', 5, 1, 'metaux-alcalins', 85.46783, 'solide', 5, 1, 5, 1, 'Rubidium is a chemical element with symbol Rb and atomic number 37. Rubidium is a soft, silvery-white metallic element of the alkali metal group, with an atomic mass of 85.4678. Elemental rubidium is highly reactive, with properties similar to those of other alkali metals, such as very rapid oxidation in air.'),
  (38, 'Sr', 'Strontium', 5, 2, 'metaux-alcalino-terreux', 87.621, 'solide', 5, 2, 5, 2, 'Strontium is a chemical element with symbol Sr and atomic number 38. An alkaline earth metal, strontium is a soft silver-white or yellowish metallic element that is highly reactive chemically. The metal turns yellow when it is exposed to air.'),
  (39, 'Y', 'Yttrium', 5, 3, 'metaux-transition', 88.905842, 'solide', 5, 3, 5, 17, 'Yttrium is a chemical element with symbol Y and atomic number 39. It is a silvery-metallic transition metal chemically similar to the lanthanides and it has often been classified as a "rare earth element". Yttrium is almost always found combined with the lanthanides in rare earth minerals and is never found in nature as a free element.'),
  (40, 'Zr', 'Zirconium', 5, 4, 'metaux-transition', 91.2242, 'solide', 5, 4, 5, 18, 'Zirconium is a chemical element with symbol Zr and atomic number 40. The name of zirconium is taken from the name of the mineral zircon, the most important source of zirconium. The word zircon comes from the Persian word zargun زرگون, meaning "gold-colored".'),
  (41, 'Nb', 'Niobium', 5, 5, 'metaux-transition', 92.906372, 'solide', 5, 5, 5, 19, 'Niobium, formerly columbium, is a chemical element with symbol Nb (formerly Cb) and atomic number 41. It is a soft, grey, ductile transition metal, which is often found in the pyrochlore mineral, the main commercial source for niobium, and columbite. The name comes from Greek mythology:Niobe, daughter of Tantalus since it is so similar to tantalum.'),
  (42, 'Mo', 'Molybdène', 5, 6, 'metaux-transition', 95.951, 'solide', 5, 6, 5, 20, 'Molybdenum is a chemical element with symbol Mo and atomic number 42. The name is from Neo-Latin molybdaenum, from Ancient Greek Μόλυβδος molybdos, meaning lead, since its ores were confused with lead ores. Molybdenum minerals have been known throughout history, but the element was discovered (in the sense of differentiating it as a new entity from the mineral salts of other metals) in 1778 by Carl Wilhelm Scheele.'),
  (43, 'Tc', 'Technétium', 5, 7, 'metaux-transition', 98, 'solide', 5, 7, 5, 21, 'Technetium (/tɛkˈniːʃiəm/) is a chemical element with symbol Tc and atomic number 43. It is the element with the lowest atomic number in the periodic table that has no stable isotopes:every form of it is radioactive. Nearly all technetium is produced synthetically, and only minute amounts are found in nature.'),
  (44, 'Ru', 'Ruthénium', 5, 8, 'metaux-transition', 101.072, 'solide', 5, 8, 5, 22, 'Ruthenium is a chemical element with symbol Ru and atomic number 44. It is a rare transition metal belonging to the platinum group of the periodic table. Like the other metals of the platinum group, ruthenium is inert to most other chemicals.'),
  (45, 'Rh', 'Rhodium', 5, 9, 'metaux-transition', 102.905502, 'solide', 5, 9, 5, 23, 'Rhodium is a chemical element with symbol Rh and atomic number 45. It is a rare, silvery-white, hard, and chemically inert transition metal. It is a member of the platinum group.'),
  (46, 'Pd', 'Palladium', 5, 10, 'metaux-transition', 106.421, 'solide', 5, 10, 5, 24, 'Palladium is a chemical element with symbol Pd and atomic number 46. It is a rare and lustrous silvery-white metal discovered in 1803 by William Hyde Wollaston. He named it after the asteroid Pallas, which was itself named after the epithet of the Greek goddess Athena, acquired by her when she slew Pallas.'),
  (47, 'Ag', 'Argent', 5, 11, 'metaux-transition', 107.86822, 'solide', 5, 11, 5, 25, 'Silver is a chemical element with symbol Ag (Greek:άργυρος árguros, Latin:argentum, both from the Indo-European root *h₂erǵ- for "grey" or "shining") and atomic number 47. A soft, white, lustrous transition metal, it possesses the highest electrical conductivity, thermal conductivity and reflectivity of any metal. The metal occurs naturally in its pure, free form (native silver), as an alloy with gold and other metals, and in minerals such as argentite and chlorargyrite.'),
  (48, 'Cd', 'Cadmium', 5, 12, 'metaux-transition', 112.4144, 'solide', 5, 12, 5, 26, 'Cadmium is a chemical element with symbol Cd and atomic number 48. This soft, bluish-white metal is chemically similar to the two other stable metals in group 12, zinc and mercury. Like zinc, it prefers oxidation state +2 in most of its compounds and like mercury it shows a low melting point compared to transition metals.'),
  (49, 'In', 'Indium', 5, 13, 'metaux-post-transition', 114.8181, 'solide', 5, 13, 5, 27, 'Indium is a chemical element with symbol In and atomic number 49. It is a post-transition metallic element that is rare in Earth''s crust. The metal is very soft, malleable and easily fusible, with a melting point higher than sodium, but lower than lithium or tin.'),
  (50, 'Sn', 'Étain', 5, 14, 'metaux-post-transition', 118.7107, 'solide', 5, 14, 5, 28, 'Tin is a chemical element with the symbol Sn (for Latin:stannum) and atomic number 50. It is a main group metal in group 14 of the periodic table. Tin shows a chemical similarity to both neighboring group-14 elements, germanium and lead, and has two possible oxidation states, +2 and the slightly more stable +4.'),
  (51, 'Sb', 'Antimoine', 5, 15, 'metalloides', 121.7601, 'solide', 5, 15, 5, 29, 'Antimony is a chemical element with symbol Sb (from Latin:stibium) and atomic number 51. A lustrous gray metalloid, it is found in nature mainly as the sulfide mineral stibnite (Sb2S3). Antimony compounds have been known since ancient times and were used for cosmetics; metallic antimony was also known, but it was erroneously identified as lead upon its discovery.'),
  (52, 'Te', 'Tellure', 5, 16, 'metalloides', 127.603, 'solide', 5, 16, 5, 30, 'Tellurium is a chemical element with symbol Te and atomic number 52. It is a brittle, mildly toxic, rare, silver-white metalloid. Tellurium is chemically related to selenium and sulfur.'),
  (53, 'I', 'Iode', 5, 17, 'non-metaux-reactifs', 126.904473, 'solide', 5, 17, 5, 31, 'Iodine is a chemical element with symbol I and atomic number 53. The name is from Greek ἰοειδής ioeidēs, meaning violet or purple, due to the color of iodine vapor. Iodine and its compounds are primarily used in nutrition, and industrially in the production of acetic acid and certain polymers.'),
  (54, 'Xe', 'Xénon', 5, 18, 'gaz-nobles', 131.2936, 'gaz', 5, 18, 5, 32, 'Xenon is a chemical element with symbol Xe and atomic number 54. It is a colorless, dense, odorless noble gas, that occurs in the Earth''s atmosphere in trace amounts. Although generally unreactive, xenon can undergo a few chemical reactions such as the formation of xenon hexafluoroplatinate, the first noble gas compound to be synthesized.'),
  (55, 'Cs', 'Césium', 6, 1, 'metaux-alcalins', 132.905451966, 'solide', 6, 1, 6, 1, 'Caesium or cesium is a chemical element with symbol Cs and atomic number 55. It is a soft, silvery-gold alkali metal with a melting point of 28 °C (82 °F), which makes it one of only five elemental metals that are liquid at or near room temperature. Caesium is an alkali metal and has physical and chemical properties similar to those of rubidium and potassium.'),
  (56, 'Ba', 'Baryum', 6, 2, 'metaux-alcalino-terreux', 137.3277, 'solide', 6, 2, 6, 2, 'Barium is a chemical element with symbol Ba and atomic number 56. It is the fifth element in Group 2, a soft silvery metallic alkaline earth metal. Because of its high chemical reactivity barium is never found in nature as a free element.'),
  (57, 'La', 'Lanthane', 6, 3, 'lanthanides', 138.905477, 'solide', 9, 3, 6, 3, 'Lanthanum is a soft, ductile, silvery-white metallic chemical element with symbol La and atomic number 57. It tarnishes rapidly when exposed to air and is soft enough to be cut with a knife. It gave its name to the lanthanide series, a group of 15 similar elements between lanthanum and lutetium in the periodic table:it is also sometimes considered the first element of the 6th-period transition metals.'),
  (58, 'Ce', 'Cérium', 6, 3, 'lanthanides', 140.1161, 'solide', 9, 4, 6, 4, 'Cerium is a chemical element with symbol Ce and atomic number 58. It is a soft, silvery, ductile metal which easily oxidizes in air. Cerium was named after the dwarf planet Ceres (itself named after the Roman goddess of agriculture).'),
  (59, 'Pr', 'Praséodyme', 6, 3, 'lanthanides', 140.907662, 'solide', 9, 5, 6, 5, 'Praseodymium is a chemical element with symbol Pr and atomic number 59. Praseodymium is a soft, silvery, malleable and ductile metal in the lanthanide group. It is valued for its magnetic, electrical, chemical, and optical properties.'),
  (60, 'Nd', 'Néodyme', 6, 3, 'lanthanides', 144.2423, 'solide', 9, 6, 6, 6, 'Neodymium is a chemical element with symbol Nd and atomic number 60. It is a soft silvery metal that tarnishes in air. Neodymium was discovered in 1885 by the Austrian chemist Carl Auer von Welsbach.'),
  (61, 'Pm', 'Prométhium', 6, 3, 'lanthanides', 145, 'solide', 9, 7, 6, 7, 'Promethium, originally prometheum, is a chemical element with the symbol Pm and atomic number 61. All of its isotopes are radioactive; it is one of only two such elements that are followed in the periodic table by elements with stable forms, a distinction shared with technetium. Chemically, promethium is a lanthanide, which forms salts when combined with other elements.'),
  (62, 'Sm', 'Samarium', 6, 3, 'lanthanides', 150.362, 'solide', 9, 8, 6, 8, 'Samarium is a chemical element with symbol Sm and atomic number 62. It is a moderately hard silvery metal that readily oxidizes in air. Being a typical member of the lanthanide series, samarium usually assumes the oxidation state +3.'),
  (63, 'Eu', 'Europium', 6, 3, 'lanthanides', 151.9641, 'solide', 9, 9, 6, 9, 'Europium is a chemical element with symbol Eu and atomic number 63. It was isolated in 1901 and is named after the continent of Europe. It is a moderately hard, silvery metal which readily oxidizes in air and water.'),
  (64, 'Gd', 'Gadolinium', 6, 3, 'lanthanides', 157.253, 'solide', 9, 10, 6, 10, 'Gadolinium is a chemical element with symbol Gd and atomic number 64. It is a silvery-white, malleable and ductile rare-earth metal. It is found in nature only in combined (salt) form.'),
  (65, 'Tb', 'Terbium', 6, 3, 'lanthanides', 158.925352, 'solide', 9, 11, 6, 11, 'Terbium is a chemical element with symbol Tb and atomic number 65. It is a silvery-white rare earth metal that is malleable, ductile and soft enough to be cut with a knife. Terbium is never found in nature as a free element, but it is contained in many minerals, including cerite, gadolinite, monazite, xenotime and euxenite.'),
  (66, 'Dy', 'Dysprosium', 6, 3, 'lanthanides', 162.5001, 'solide', 9, 12, 6, 12, 'Dysprosium is a chemical element with the symbol Dy and atomic number 66. It is a rare earth element with a metallic silver luster. Dysprosium is never found in nature as a free element, though it is found in various minerals, such as xenotime.'),
  (67, 'Ho', 'Holmium', 6, 3, 'lanthanides', 164.930332, 'solide', 9, 13, 6, 13, 'Holmium is a chemical element with symbol Ho and atomic number 67. Part of the lanthanide series, holmium is a rare earth element. Holmium was discovered by Swedish chemist Per Theodor Cleve.'),
  (68, 'Er', 'Erbium', 6, 3, 'lanthanides', 167.2593, 'solide', 9, 14, 6, 14, 'Erbium is a chemical element in the lanthanide series, with symbol Er and atomic number 68. A silvery-white solid metal when artificially isolated, natural erbium is always found in chemical combination with other elements on Earth. As such, it is a rare earth element which is associated with several other rare elements in the mineral gadolinite from Ytterby in Sweden, where yttrium, ytterbium, and terbium were discovered.'),
  (69, 'Tm', 'Thulium', 6, 3, 'lanthanides', 168.934222, 'solide', 9, 15, 6, 15, 'Thulium is a chemical element with symbol Tm and atomic number 69. It is the thirteenth and antepenultimate (third-last) element in the lanthanide series. Like the other lanthanides, the most common oxidation state is +3, seen in its oxide, halides and other compounds.'),
  (70, 'Yb', 'Ytterbium', 6, 3, 'lanthanides', 173.0451, 'solide', 9, 16, 6, 16, 'Ytterbium is a chemical element with symbol Yb and atomic number 70. It is the fourteenth and penultimate element in the lanthanide series, which is the basis of the relative stability of its +2 oxidation state. However, like the other lanthanides, its most common oxidation state is +3, seen in its oxide, halides and other compounds.'),
  (71, 'Lu', 'Lutécium', 6, 3, 'lanthanides', 174.96681, 'solide', 9, 17, 6, 17, 'Lutetium is a chemical element with symbol Lu and atomic number 71. It is a silvery white metal, which resists corrosion in dry, but not in moist air. It is considered the first element of the 6th-period transition metals and the last element in the lanthanide series, and is traditionally counted among the rare earths.'),
  (72, 'Hf', 'Hafnium', 6, 4, 'metaux-transition', 178.492, 'solide', 6, 4, 6, 18, 'Hafnium is a chemical element with symbol Hf and atomic number 72. A lustrous, silvery gray, tetravalent transition metal, hafnium chemically resembles zirconium and is found in zirconium minerals. Its existence was predicted by Dmitri Mendeleev in 1869, though it was not identified until 1923, making it the penultimate stable element to be discovered (rhenium was identified two years later).'),
  (73, 'Ta', 'Tantale', 6, 5, 'metaux-transition', 180.947882, 'solide', 6, 5, 6, 19, 'Tantalum is a chemical element with symbol Ta and atomic number 73. Previously known as tantalium, its name comes from Tantalus, an antihero from Greek mythology. Tantalum is a rare, hard, blue-gray, lustrous transition metal that is highly corrosion-resistant.'),
  (74, 'W', 'Tungstène', 6, 6, 'metaux-transition', 183.841, 'solide', 6, 6, 6, 20, 'Tungsten, also known as wolfram, is a chemical element with symbol W and atomic number 74. The word tungsten comes from the Swedish language tung sten, which directly translates to heavy stone. Its name in Swedish is volfram, however, in order to distinguish it from scheelite, which in Swedish is alternatively named tungsten.'),
  (75, 'Re', 'Rhénium', 6, 7, 'metaux-transition', 186.2071, 'solide', 6, 7, 6, 21, 'Rhenium is a chemical element with symbol Re and atomic number 75. It is a silvery-white, heavy, third-row transition metal in group 7 of the periodic table. With an estimated average concentration of 1 part per billion (ppb), rhenium is one of the rarest elements in the Earth''s crust.'),
  (76, 'Os', 'Osmium', 6, 8, 'metaux-transition', 190.233, 'solide', 6, 8, 6, 22, 'Osmium (from Greek osme (ὀσμή) meaning "smell") is a chemical element with symbol Os and atomic number 76. It is a hard, brittle, bluish-white transition metal in the platinum group that is found as a trace element in alloys, mostly in platinum ores. Osmium is the densest naturally occurring element, with a density of 22.59 g/cm3.'),
  (77, 'Ir', 'Iridium', 6, 9, 'metaux-transition', 192.2173, 'solide', 6, 9, 6, 23, 'Iridium is a chemical element with symbol Ir and atomic number 77. A very hard, brittle, silvery-white transition metal of the platinum group, iridium is generally credited with being the second densest element (after osmium) based on measured density, although calculations involving the space lattices of the elements show that iridium is denser. It is also the most corrosion-resistant metal, even at temperatures as high as 2000 °C. Although only certain molten salts and halogens are corrosive to solid iridium, finely divided iridium dust is much more reactive and can be flammable.'),
  (78, 'Pt', 'Platine', 6, 10, 'metaux-transition', 195.0849, 'solide', 6, 10, 6, 24, 'Platinum is a chemical element with symbol Pt and atomic number 78. It is a dense, malleable, ductile, highly unreactive, precious, gray-white transition metal. Its name is derived from the Spanish term platina, which is literally translated into "little silver".'),
  (79, 'Au', 'Or', 6, 11, 'metaux-transition', 196.9665695, 'solide', 6, 11, 6, 25, 'Gold is a chemical element with symbol Au (from Latin:aurum) and atomic number 79. In its purest form, it is a bright, slightly reddish yellow, dense, soft, malleable and ductile metal. Chemically, gold is a transition metal and a group 11 element.'),
  (80, 'Hg', 'Mercure', 6, 12, 'metaux-transition', 200.5923, 'liquide', 6, 12, 6, 26, 'Mercury is a chemical element with symbol Hg and atomic number 80. It is commonly known as quicksilver and was formerly named hydrargyrum (/haɪˈdrɑːrdʒərəm/). A heavy, silvery d-block element, mercury is the only metallic element that is liquid at standard conditions for temperature and pressure; the only other element that is liquid under these conditions is bromine, though metals such as caesium, gallium, and rubidium melt just above room temperature.'),
  (81, 'Tl', 'Thallium', 6, 13, 'metaux-post-transition', 204.38, 'solide', 6, 13, 6, 27, 'Thallium is a chemical element with symbol Tl and atomic number 81. This soft gray post-transition metal is not found free in nature. When isolated, it resembles tin, but discolors when exposed to air.'),
  (82, 'Pb', 'Plomb', 6, 14, 'metaux-post-transition', 207.21, 'solide', 6, 14, 6, 28, 'Lead (/lɛd/) is a chemical element in the carbon group with symbol Pb (from Latin:plumbum) and atomic number 82. Lead is a soft, malleable and heavy post-transition metal. Metallic lead has a bluish-white color after being freshly cut, but it soon tarnishes to a dull grayish color when exposed to air.'),
  (83, 'Bi', 'Bismuth', 6, 15, 'metaux-post-transition', 208.980401, 'solide', 6, 15, 6, 29, 'Bismuth is a chemical element with symbol Bi and atomic number 83. Bismuth, a pentavalent post-transition metal, chemically resembles arsenic and antimony. Elemental bismuth may occur naturally, although its sulfide and oxide form important commercial ores.'),
  (84, 'Po', 'Polonium', 6, 16, 'metaux-post-transition', 209, 'solide', 6, 16, 6, 30, 'Polonium is a chemical element with symbol Po and atomic number 84, discovered in 1898 by Marie Curie and Pierre Curie. A rare and highly radioactive element with no stable isotopes, polonium is chemically similar to bismuth and tellurium, and it occurs in uranium ores. Applications of polonium are few.'),
  (85, 'At', 'Astate', 6, 17, 'metalloides', 210, 'solide', 6, 17, 6, 31, 'Astatine is a very rare radioactive chemical element with the chemical symbol At and atomic number 85. It occurs on Earth as the decay product of various heavier elements. All its isotopes are short-lived; the most stable is astatine-210, with a half-life of 8.1 hours.'),
  (86, 'Rn', 'Radon', 6, 18, 'gaz-nobles', 222, 'gaz', 6, 18, 6, 32, 'Radon is a chemical element with symbol Rn and atomic number 86. It is a radioactive, colorless, odorless, tasteless noble gas, occurring naturally as a decay product of radium. Its most stable isotope, 222Rn, has a half-life of 3.8 days.'),
  (87, 'Fr', 'Francium', 7, 1, 'metaux-alcalins', 223, 'solide', 7, 1, 7, 1, 'Francium is a chemical element with symbol Fr and atomic number 87. It used to be known as eka-caesium and actinium K. It is the second-least electronegative element, behind only caesium. Francium is a highly radioactive metal that decays into astatine, radium, and radon.'),
  (88, 'Ra', 'Radium', 7, 2, 'metaux-alcalino-terreux', 226, 'solide', 7, 2, 7, 2, 'Radium is a chemical element with symbol Ra and atomic number 88. It is the sixth element in group 2 of the periodic table, also known as the alkaline earth metals. Pure radium is almost colorless, but it readily combines with nitrogen (rather than oxygen) on exposure to air, forming a black surface layer of radium nitride (Ra3N2).'),
  (89, 'Ac', 'Actinium', 7, 3, 'actinides', 227, 'solide', 10, 3, 7, 3, 'Actinium is a radioactive chemical element with symbol Ac (not to be confused with the abbreviation for an acetyl group) and atomic number 89, which was discovered in 1899. It was the first non-primordial radioactive element to be isolated. Polonium, radium and radon were observed before actinium, but they were not isolated until 1902.'),
  (90, 'Th', 'Thorium', 7, 3, 'actinides', 232.03774, 'solide', 10, 4, 7, 4, 'Thorium is a chemical element with symbol Th and atomic number 90. A radioactive actinide metal, thorium is one of only two significantly radioactive elements that still occur naturally in large quantities as a primordial element (the other being uranium). It was discovered in 1828 by the Norwegian Reverend and amateur mineralogist Morten Thrane Esmark and identified by the Swedish chemist Jöns Jakob Berzelius, who named it after Thor, the Norse god of thunder.'),
  (91, 'Pa', 'Protactinium', 7, 3, 'actinides', 231.035882, 'solide', 10, 5, 7, 5, 'Protactinium is a chemical element with symbol Pa and atomic number 91. It is a dense, silvery-gray metal which readily reacts with oxygen, water vapor and inorganic acids. It forms various chemical compounds where protactinium is usually present in the oxidation state +5, but can also assume +4 and even +2 or +3 states.'),
  (92, 'U', 'Uranium', 7, 3, 'actinides', 238.028913, 'solide', 10, 6, 7, 6, 'Uranium is a chemical element with symbol U and atomic number 92. It is a silvery-white metal in the actinide series of the periodic table. A uranium atom has 92 protons and 92 electrons, of which 6 are valence electrons.'),
  (93, 'Np', 'Neptunium', 7, 3, 'actinides', 237, 'solide', 10, 7, 7, 7, 'Neptunium is a chemical element with symbol Np and atomic number 93. A radioactive actinide metal, neptunium is the first transuranic element. Its position in the periodic table just after uranium, named after the planet Uranus, led to it being named after Neptune, the next planet beyond Uranus.'),
  (94, 'Pu', 'Plutonium', 7, 3, 'actinides', 244, 'solide', 10, 8, 7, 8, 'Plutonium is a transuranic radioactive chemical element with symbol Pu and atomic number 94. It is an actinide metal of silvery-gray appearance that tarnishes when exposed to air, and forms a dull coating when oxidized. The element normally exhibits six allotropes and four oxidation states.'),
  (95, 'Am', 'Américium', 7, 3, 'actinides', 243, 'solide', 10, 9, 7, 9, 'Americium is a radioactive transuranic chemical element with symbol Am and atomic number 95. This member of the actinide series is located in the periodic table under the lanthanide element europium, and thus by analogy was named after the Americas. Americium was first produced in 1944 by the group of Glenn T.Seaborg from Berkeley, California, at the metallurgical laboratory of University of Chicago.'),
  (96, 'Cm', 'Curium', 7, 3, 'actinides', 247, 'solide', 10, 10, 7, 10, 'Curium is a transuranic radioactive chemical element with symbol Cm and atomic number 96. This element of the actinide series was named after Marie and Pierre Curie – both were known for their research on radioactivity. Curium was first intentionally produced and identified in July 1944 by the group of Glenn T. Seaborg at the University of California, Berkeley.'),
  (97, 'Bk', 'Berkélium', 7, 3, 'actinides', 247, 'solide', 10, 11, 7, 11, 'Berkelium is a transuranic radioactive chemical element with symbol Bk and atomic number 97. It is a member of the actinide and transuranium element series. It is named after the city of Berkeley, California, the location of the University of California Radiation Laboratory where it was discovered in December 1949.'),
  (98, 'Cf', 'Californium', 7, 3, 'actinides', 251, 'solide', 10, 12, 7, 12, 'Californium is a radioactive metallic chemical element with symbol Cf and atomic number 98. The element was first made in 1950 at the University of California Radiation Laboratory in Berkeley, by bombarding curium with alpha particles (helium-4 ions). It is an actinide element, the sixth transuranium element to be synthesized, and has the second-highest atomic mass of all the elements that have been produced in amounts large enough to see with the unaided eye (after einsteinium).'),
  (99, 'Es', 'Einsteinium', 7, 3, 'actinides', 252, 'solide', 10, 13, 7, 13, 'Einsteinium is a synthetic element with symbol Es and atomic number 99. It is the seventh transuranic element, and an actinide. Einsteinium was discovered as a component of the debris of the first hydrogen bomb explosion in 1952, and named after Albert Einstein.'),
  (100, 'Fm', 'Fermium', 7, 3, 'actinides', 257, 'solide', 10, 14, 7, 14, 'Fermium is a synthetic element with symbol Fm and atomic number 100. It is a member of the actinide series. It is the heaviest element that can be formed by neutron bombardment of lighter elements, and hence the last element that can be prepared in macroscopic quantities, although pure fermium metal has not yet been prepared.'),
  (101, 'Md', 'Mendélévium', 7, 3, 'actinides', 258, 'solide', 10, 15, 7, 15, 'Mendelevium is a synthetic element with chemical symbol Md (formerly Mv) and atomic number 101. A metallic radioactive transuranic element in the actinide series, it is the first element that currently cannot be produced in macroscopic quantities through neutron bombardment of lighter elements. It is the antepenultimate actinide and the ninth transuranic element.'),
  (102, 'No', 'Nobélium', 7, 3, 'actinides', 259, 'solide', 10, 16, 7, 16, 'Nobelium is a synthetic chemical element with symbol No and atomic number 102. It is named in honor of Alfred Nobel, the inventor of dynamite and benefactor of science. A radioactive metal, it is the tenth transuranic element and is the penultimate member of the actinide series.'),
  (103, 'Lr', 'Lawrencium', 7, 3, 'actinides', 266, 'solide', 10, 17, 7, 17, 'Lawrencium is a synthetic chemical element with chemical symbol Lr (formerly Lw) and atomic number 103. It is named in honor of Ernest Lawrence, inventor of the cyclotron, a device that was used to discover many artificial radioactive elements. A radioactive metal, lawrencium is the eleventh transuranic element and is also the final member of the actinide series.'),
  (104, 'Rf', 'Rutherfordium', 7, 4, 'metaux-transition', 267, 'solide', 7, 4, 7, 18, 'Rutherfordium is a chemical element with symbol Rf and atomic number 104, named in honor of physicist Ernest Rutherford. It is a synthetic element (an element that can be created in a laboratory but is not found in nature) and radioactive; the most stable known isotope, 267Rf, has a half-life of approximately 1.3 hours. In the periodic table of the elements, it is a d - block element and the second of the fourth - row transition elements.'),
  (105, 'Db', 'Dubnium', 7, 5, 'metaux-transition', 268, 'solide', 7, 5, 7, 19, 'Dubnium is a chemical element with symbol Db and atomic number 105. It is named after the town of Dubna in Russia (north of Moscow), where it was first produced. It is a synthetic element (an element that can be created in a laboratory but is not found in nature) and radioactive; the most stable known isotope, dubnium-268, has a half-life of approximately 28 hours.'),
  (106, 'Sg', 'Seaborgium', 7, 6, 'metaux-transition', 269, 'solide', 7, 6, 7, 20, 'Seaborgium is a synthetic element with symbol Sg and atomic number 106. Its most stable isotope 271Sg has a half-life of 1.9 minutes. A more recently discovered isotope 269Sg has a potentially slightly longer half-life (ca.'),
  (107, 'Bh', 'Bohrium', 7, 7, 'metaux-transition', 270, 'solide', 7, 7, 7, 21, 'Bohrium is a chemical element with symbol Bh and atomic number 107. It is named after Danish physicist Niels Bohr. It is a synthetic element (an element that can be created in a laboratory but is not found in nature) and radioactive; the most stable known isotope, 270Bh, has a half-life of approximately 61 seconds.'),
  (108, 'Hs', 'Hassium', 7, 8, 'metaux-transition', 269, 'solide', 7, 8, 7, 22, 'Hassium is a chemical element with symbol Hs and atomic number 108, named after the German state of Hesse. It is a synthetic element (an element that can be created in a laboratory but is not found in nature) and radioactive; the most stable known isotope, 269Hs, has a half-life of approximately 9.7 seconds, although an unconfirmed metastable state, 277mHs, may have a longer half-life of about 130 seconds. More than 100 atoms of hassium have been synthesized to date.'),
  (109, 'Mt', 'Meitnerium', 7, 9, 'proprietes-inconnues', 278, 'solide', 7, 9, 7, 23, 'Meitnerium is a chemical element with symbol Mt and atomic number 109. It is an extremely radioactive synthetic element (an element not found in nature that can be created in a laboratory). The most stable known isotope, meitnerium-278, has a half-life of 7.6 seconds.'),
  (110, 'Ds', 'Darmstadtium', 7, 10, 'proprietes-inconnues', 281, 'solide', 7, 10, 7, 24, 'Darmstadtium is a chemical element with symbol Ds and atomic number 110. It is an extremely radioactive synthetic element. The most stable known isotope, darmstadtium-281, has a half-life of approximately 10 seconds.'),
  (111, 'Rg', 'Roentgenium', 7, 11, 'proprietes-inconnues', 282, 'solide', 7, 11, 7, 25, 'Roentgenium is a chemical element with symbol Rg and atomic number 111. It is an extremely radioactive synthetic element (an element that can be created in a laboratory but is not found in nature); the most stable known isotope, roentgenium-282, has a half-life of 2.1 minutes. Roentgenium was first created in 1994 by the GSI Helmholtz Centre for Heavy Ion Research near Darmstadt, Germany.'),
  (112, 'Cn', 'Copernicium', 7, 12, 'metaux-transition', 285, 'liquide', 7, 12, 7, 26, 'Copernicium is a chemical element with symbol Cn and atomic number 112. It is an extremely radioactive synthetic element that can only be created in a laboratory. The most stable known isotope, copernicium-285, has a half-life of approximately 29 seconds, but it is possible that this copernicium isotope may have a nuclear isomer with a longer half-life, 8.9 min.'),
  (113, 'Nh', 'Nihonium', 7, 13, 'proprietes-inconnues', 286, 'solide', 7, 13, 7, 27, 'Nihonium is a chemical element with atomic number 113. It has a symbol Nh. It is a synthetic element (an element that can be created in a laboratory but is not found in nature) and is extremely radioactive; its most stable known isotope, nihonium-286, has a half-life of 20 seconds.'),
  (114, 'Fl', 'Flérovium', 7, 14, 'metaux-post-transition', 289, 'solide', 7, 14, 7, 28, 'Flerovium is a superheavy artificial chemical element with symbol Fl and atomic number 114. It is an extremely radioactive synthetic element. The element is named after the Flerov Laboratory of Nuclear Reactions of the Joint Institute for Nuclear Research in Dubna, Russia, where the element was discovered in 1998.'),
  (115, 'Mc', 'Moscovium', 7, 15, 'proprietes-inconnues', 289, 'solide', 7, 15, 7, 29, 'Moscovium is the name of a synthetic superheavy element in the periodic table that has the symbol Mc and has the atomic number 115. It is an extremely radioactive element; its most stable known isotope, moscovium-289, has a half-life of only 220 milliseconds. It is also known as eka-bismuth or simply element 115.'),
  (116, 'Lv', 'Livermorium', 7, 16, 'proprietes-inconnues', 293, 'solide', 7, 16, 7, 30, 'Livermorium is a synthetic superheavy element with symbol Lv and atomic number 116. It is an extremely radioactive element that has only been created in the laboratory and has not been observed in nature. The element is named after the Lawrence Livermore National Laboratory in the United States, which collaborated with the Joint Institute for Nuclear Research in Dubna, Russia to discover livermorium in 2000.'),
  (117, 'Ts', 'Tennesse', 7, 17, 'proprietes-inconnues', 294, 'solide', 7, 17, 7, 31, 'Tennessine is a superheavy artificial chemical element with an atomic number of 117 and a symbol of Ts. Also known as eka-astatine or element 117, it is the second-heaviest known element and penultimate element of the 7th period of the periodic table. As of 2016, fifteen tennessine atoms have been observed:six when it was first synthesized in 2010, seven in 2012, and two in 2014.'),
  (118, 'Og', 'Oganesson', 7, 18, 'proprietes-inconnues', 294, 'solide', 7, 18, 7, 32, 'Oganesson is IUPAC''s name for the transactinide element with the atomic number 118 and element symbol Og. It is also known as eka-radon or element 118, and on the periodic table of the elements it is a p-block element and the last one of the 7th period. Oganesson is currently the only synthetic member of group 18.'),
  (119, 'Uue', 'Ununennium', 8, 1, 'proprietes-inconnues', 315, 'solide', 8, 1, 8, 1, 'Ununennium, also known as eka-francium or simply element 119, is the hypothetical chemical element with symbol Uue and atomic number 119. Ununennium and Uue are the temporary systematic IUPAC name and symbol respectively, until a permanent name is decided upon. In the periodic table of the elements, it is expected to be an s-block element, an alkali metal, and the first element in the eighth period.')
ON CONFLICT (numero_atomique) DO UPDATE SET
  symbole        = EXCLUDED.symbole,
  nom            = EXCLUDED.nom,
  periode        = EXCLUDED.periode,
  groupe         = EXCLUDED.groupe,
  famille        = EXCLUDED.famille,
  masse_atomique = EXCLUDED.masse_atomique,
  etat_standard  = EXCLUDED.etat_standard,
  grid_row       = EXCLUDED.grid_row,
  grid_col       = EXCLUDED.grid_col,
  wgrid_row      = EXCLUDED.wgrid_row,
  wgrid_col      = EXCLUDED.wgrid_col,
  summary_fr     = EXCLUDED.summary_fr;

-- Index sur famille (déjà créé en 0009 mais idempotent).
CREATE INDEX IF NOT EXISTS periodic_elements_famille_idx
  ON public.periodic_elements (famille);

